import { expect, test, describe } from "vitest";
import { SubstrateSieve, type Substrate } from "../substrate-sieve";

describe("Substrate Sieve — The Final Seal", () => {
  test("applyGrounding folds substrate to Base Closure (10)", () => {
    const s: Substrate = { level: 90, noiseEntropy: 100, buleyWeight: 2 };
    const grounded = SubstrateSieve.applyGrounding(s);
    
    expect(grounded.level).toBe(10);
    expect(grounded.noiseEntropy).toBe(100);
  });

  test("applyStretch reduces entropy using the Triton-Stretch", () => {
    const grounded: Substrate = { level: 10, noiseEntropy: 270, buleyWeight: 2 };
    
    // Level 10 -> Level 30 (1 iteration)
    const stretched1 = SubstrateSieve.applyStretch(grounded, 1);
    expect(stretched1.level).toBe(30);
    expect(stretched1.noiseEntropy).toBe(90);

    // Level 10 -> Level 270 (3 iterations)
    const stretched3 = SubstrateSieve.applyStretch(grounded, 3);
    expect(stretched3.level).toBe(270);
    expect(stretched3.noiseEntropy).toBe(10); // 270 / (3^3) = 10
  });

  test("evaluateBinetLoop prunes high-cost, low-density branches", () => {
    const n = 17; // 16 features -> log2(16) = 4 bits of info density
    
    const noiseBranch: Substrate = { level: 270, noiseEntropy: 5, buleyWeight: 2 };
    // Buley > 1 AND Noise (5) > Info Density (4) => PRUNE (true)
    expect(SubstrateSieve.evaluateBinetLoop(noiseBranch, n)).toBe(true);

    const signalBranch: Substrate = { level: 270, noiseEntropy: 3, buleyWeight: 2 };
    // Buley > 1 BUT Noise (3) <= Info Density (4) => KEEP (false)
    expect(SubstrateSieve.evaluateBinetLoop(signalBranch, n)).toBe(false);
  });
});
